local payTabs = MemoryPool.newTable()

PayShopTabsConfig = {}

function PayShopTabsConfig:loadConfig()

    local temp = FileUtil.getConfigFromCsv("setting/PayShopTab.csv", 3)
    for _, Value in pairs(temp) do
        table.insert(payTabs,{
            Id = tonumber(Value.n_Id),
            Type = tonumber(Value.n_Type),
            Icon = Value.s_Icon,
            Name = Value.s_Name
        })

    end
    --print("--------------------------------")
    --print(json.encode(payTabs))
end

function PayShopTabsConfig:getTabs()
    return payTabs
end


function PayShopTabsConfig:getTabsById(Id)
    for _, Value in pairs(payTabs) do
        if Value.Id == Id then
            return Value
        end
    end
    return nil
end